const lead = $input.first().json.body || $input.first().json;

// Validar campos requeridos
const required = ['name', 'email', 'company', 'message'];
const missing = required.filter(f => !lead[f]);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Enriquecer datos del lead
const enriched = {
  id: `LEAD-${Date.now()}`,
  timestamp: new Date().toISOString(),
  name: lead.name.trim(),
  email: lead.email.toLowerCase().trim(),
  company: lead.company.trim(),
  message: lead.message.trim(),
  phone: lead.phone || 'Not provided',
  source: lead.source || 'Website',
  // Extraer dominio del email para análisis
  emailDomain: lead.email.split('@')[1],
  // Calcular longitud del mensaje como señal de intención
  messageLength: lead.message.length,
  messageWords: lead.message.split(' ').length
};

return { json: enriched };

const lead = $('Validate & Enrich Lead').first().json;
let aiRaw = $input.first().json.response || $input.first().json.text || '';

// Limpiar respuesta del LLM (remover markdown si viene)
aiRaw = aiRaw.replace(/```json/g, '').replace(/```/g, '').trim();

let qualification;
try {
  qualification = JSON.parse(aiRaw);
} catch(e) {
  // Fallback si el LLM no responde en JSON válido
  qualification = {
    score: 50,
    tier: 'WARM',
    intent: 'Medium',
    budget_signals: 'Unknown',
    urgency: 'Unknown',
    recommended_action: 'Manual review required',
    follow_up_within: '24 hours',
    key_insights: ['AI parsing error - manual review needed'],
    risk_flags: ['Could not parse AI response'],
    personalized_opener: `Hi ${lead.name}, thank you for reaching out.`
  };
}

// Combinar todo en un objeto final
const result = {
  ...lead,
  qualification,
  // Color para dashboard
  tierColor: qualification.tier === 'HOT' ? '#FF4444' : qualification.tier === 'WARM' ? '#FF8C00' : '#4444FF',
  // Prioridad numérica para ordenar
  priority: qualification.tier === 'HOT' ? 1 : qualification.tier === 'WARM' ? 2 : 3,
  processedAt: new Date().toISOString()
};

return { json: result };
